const Q_ECONOMICS_2024_MODEL_II=[{"id": "objective>Economics>2024 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the equation Q = a - bp + e; Q and P are .................................................... Variables respectively.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dependent and independent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">error term and independent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">independent and constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">independent and dependent</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given equation, Q represents the dependent variable, which means it is the variable that is being explained or predicted based on the values of other variables. In this case, Q is the dependent variable because its value depends on the values of other variables in the equation. <br/>  <br/> On the other hand, P represents the independent variable, which means it is the variable that is being manipulated or controlled and is expected to have an effect on the dependent variable. In this equation, P is the independent variable as its value can be changed or adjusted independently of other variables to observe its impact on Q.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : ELEMENTARY THEORY OF INCOME DETERMINATION"}, {"id": "objective>Economics>2024 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Persistent fall In the general price level Is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">devaluation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">general price Increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deflation refers to a persistent fall in the general price level of goods and services in an economy over a period of time. It means that, on average, prices are decreasing, and the purchasing power of money is increasing. Deflation can occur due to factors such as a decrease in the money supply, lower production costs, or reduced consumer demand.</div>", "topic": "INFLATION & DEFLATION : INTRODUCTION"}, {"id": "objective>Economics>2024 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economy in which decision of what to produce is taken partly by private individuals and state is referred to as ......................economy.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capitalist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socialist</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixed economy is an economic system that incorporates elements of both capitalism and socialism. In a mixed economy, the decision of what to produce is taken partly by private individuals and partly by the state or government. This means that there is a combination of privately-owned businesses and government intervention in economic activities.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2024 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An industry operating in a perfect competitive market situation will maximum profit when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> DD < SS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC > AC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC < AR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC = MR</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In perfect competition, a firm's marginal cost (MC) represents the additional cost incurred by producing one more unit of output, while marginal revenue (MR) represents the additional revenue generated from selling one more unit of output. To maximize profit, a firm in a perfectly competitive market will produce at the quantity where marginal cost equals marginal revenue. <br/>  <br/> When MC is less than MR (MC < MR), producing an additional unit of output will generate more revenue than the cost incurred, indicating that increasing production is profitable. Conversely, when MC is greater than MR (MC > MR), producing an additional unit of output would result in higher costs than the revenue generated, leading to a decrease in profit. The profit is maximized at the quantity where MC is equal to MR.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2024 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The satisfaction derived from the consumption of a commodity is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Utility is the satisfaction a consumer derived from the consumption of a particular commodity.  The types are: total, average and marginal utility.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>2024 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand for factors of production is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">complementary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">derived</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of derived demand refers to the demand for a factor of production, such as labour or capital, that is derived from the demand for the final goods or services that the factor helps to produce. In other words, the demand for factors of production is derived from the demand for the products that require those factors. <br/>  <br/> For example, the demand for labour in the construction industry is derived from the demand for new houses or buildings. If there is an increase in the demand for housing, it will lead to an increase in the demand for construction workers.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : WAGES"}, {"id": "objective>Economics>2024 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a disadvantage of localization of industries?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Creating structural unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Encouraging subsidiary industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Encouraging the growth of skilled labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reducing cost of production</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Localization of industries, also known as industrial clustering or agglomeration, refers to the concentration of similar industries or related businesses in a specific geographic area. While there are various advantages associated with localization, such as promoting knowledge spillovers, fostering collaboration, and enhancing economies of scale, it can also have disadvantages. <br/>  <br/> One of the disadvantages is the creation of structural unemployment. When industries concentrate in a particular region, job opportunities may become limited to that specific area. As a result, workers in other regions or industries may face challenges in finding employment, leading to structural unemployment. This can be particularly problematic if the localized industry experiences a decline or faces disruptions, resulting in job losses for a significant portion of the workforce.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2024 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At the equilibrium price,</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand is greater than supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand equates supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand is less than supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price is equal to demand only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium price is the price at which the quantity demanded by consumers equals the quantity supplied by producers in a market. It represents the point of balance between demand and supply. <br/>  <br/> At the equilibrium price, the quantity that consumers are willing to buy (demand) matches the quantity that producers are willing to sell (supply). There is no shortage or surplus in the market because the quantity demanded and the quantity supplied are in equilibrium.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2024 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the correct order in the chain of distribution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Consumer -> Distributor → Retailer → Producer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Producer → Consumer → Retailer → Wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Producer → Wholesaler → Retailer → Consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Retailer → Consumer → Producer → Wholesaler</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct order in the chain of distribution is:  Producer → Wholesaler → Retailer → Consumer. <br/>  <br/> In this distribution chain, the products or goods flow from the producer to the wholesaler, then to the retailer, and finally to the consumer.</div>", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION"}, {"id": "objective>Economics>2024 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are rewards for factors of production EXCEPT</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> interest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subsidy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factors of production are the resources or inputs used in the production process, including land, labor, capital, and entrepreneurship. Each factor receives a specific reward or payment for its contribution to the production process. The rewards for factors of production are as follows: Rent, Wages(Salaries), Interest and Profit</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : RENT & INTEREST"}, {"id": "objective>Economics>2024 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under perfect competition, a profit maximizing firm will hire labour up to the point where the last unit of labor adds</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">as much to TR as to TC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less to TR as to TC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less to TC than to TR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more to TC than to TR</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under perfect competition, a profit-maximizing firm will hire labor up to the point where the marginal revenue product of labor (MRP) is equal to the wage rate. MRP represents the additional revenue generated by adding one more unit of labor. <br/>  <br/> Since the firm aims to maximize profits, it will continue hiring labor until the MRP is greater than or equal to the wage rate. At this point, the last unit of labor hired contributes more to total revenue than to total cost, resulting in increased profits for the firm.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}, {"id": "objective>Economics>2024 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of tax and expenditure policy to regulate the economy is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deregulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fiscal policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monetary policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physical measures</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy refers to the use of government spending and taxation to influence the overall economy. It involves the use of taxes and government expenditures to stabilize the economy, promote economic growth, control inflation, and manage other macroeconomic objectives. Fiscal policy can be expansionary (increasing government spending and/or reducing taxes) or contractionary (reducing government spending and/or increasing taxes) based on the economic conditions and policy goals.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2024 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the population of a school is 600 and 60% are In JSS, how many students are in SSS?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">204</div>", "<div style=\"font-family:Cambria;font-size:17px;\">224</div>", "<div style=\"font-family:Cambria;font-size:17px;\">240</div>", "<div style=\"font-family:Cambria;font-size:17px;\">244</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Number of students in JSS = 60% of 600  <br/> = 0.60 x 600 = 360 <br/>  <br/> Since the remaining students are in SSS, we can calculate the number of students in SSS: <br/> Number of students in SSS = Total school population - Number of students in JSS <br/> Number of students in SSS = 600 - 360  <br/> = 240</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2024 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT associated with minimum price legislation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excess demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wastages of resources</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Minimum price legislation, also known as price floors, is a form of government intervention that establishes a legally mandated minimum price for a particular good or service. The purpose is to ensure that producers receive a certain level of income or to protect certain industries. The effects are:  <br/> a.\tExcess supply over demand <br/> b.\tInflationary result from price increase <br/> c.\tA waste of perishable products occur <br/> d.\tUnemployment will result from excess supply of labour <br/> e.\tInefficiency in the use of production resources</div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2024 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are problems of development planning in Nigeria EXCEPT</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inadequate capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate statistical data</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor implementation of economic planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">under-population</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The problems of development planning in Nigeria include issues such as the death of skilled manpower, inadequate capital, inadequate statistical data, and poor implementation of economic planning. These factors can pose significant challenges to the planning and execution of development initiatives. <br/>  <br/> However, under-population is not typically considered a problem of development planning in Nigeria. Nigeria is one of the most populous countries in the world, with a large and growing population. Overpopulation or population growth may present its own set of challenges, but it is not commonly listed as a problem in the context of development planning in the country.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2024 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT included in-measuring the National income through the income approach?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Allowance given to an aged mother by a civil servant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Income earned by a bricklayer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Profit earned by Nigerian bottling company plc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit earned by NITEL plc</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The income approach is one of the methods used to measure national income, which calculates national income by summing up all the incomes earned by different factors of production within an economy. However, the allowance given to an aged mother by a civil servant would not be included in the measurement of national income through the income approach. <br/>  <br/> The income approach typically includes the following components: <br/> -  Wages and salaries earned by individuals, such as the income earned by a bricklayer and the salary earned by a doctor. <br/> -  Profits earned by businesses, such as the profit earned by Nigerian Bottling Company Plc and NITEL Plc. <br/> -  Rent earned from the use of property and land. <br/> -  Interest earned on savings and investments. <br/>  <br/> Allowances given to individuals by civil servants, is not considered as part of national income because they do not represent income generated from production or factor inputs within the economy.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2024 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major characteristics of a firm operating at a long-run equilibrium position is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all costs can be varied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average variable cost is fixed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed cost can not be changed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only variable cost changes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major characteristic of a firm operating at a long-run equilibrium position is that all costs can be varied. In the long run, a firm has flexibility in adjusting its inputs and production level to optimize its operations. <br/>  <br/> In the long run, a firm can make adjustments to various factors of production, such as labor, capital, and technology. This flexibility allows the firm to change its costs according to the desired level of output. Fixed costs, such as rent for a facility, can be adjusted by choosing a different location or size of the facility. Variable costs, such as raw materials and labor, can also be adjusted by changing the quantity of inputs used.</div>", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2024 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The problem of \"how to produce\" in any economy is solved by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adopting the least cost method of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">combining capital and labour intensive methods of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">employing the services of a manager</div>", "<div style=\"font-family:Cambria;font-size:17px;\">using capital intensive method of production</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The problem of \"how to produce\" in any economy refers to the decision of choosing the most efficient and effective methods of production. This decision involves considering factors such as the available resources, technology, and the desired level of output. The goal is to minimize costs while maximizing productivity.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2024 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT an objective of Economic planning?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Achieving economic growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Creating employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equitable allocation of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Widening the income gap</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Widening the income gap is not an objective of economic planning. Economic planning typically aims to address socio-economic challenges and achieve certain developmental goals. Instead, economic planning often aims to reduce income inequalities and promote inclusive growth that benefits a broader segment of the population.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2024 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following will occur when maximum price is fixed below the free market price EXCEPT that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">black market will be encouraged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess demand will occur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess supply will occur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rationing of commodities will occur</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maximum price is fixed above the equilibrium price to protect the consumers or the buyers. When the price is fixed below the equilibrium price, there will be excess demand over supply and it will lead to: <br/> - rationing <br/> - hoarding <br/> - black market <br/> - bribery and corruption</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2024 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following determine the level of consumption EXCEPT</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">level of income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">savings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rate of taxes paid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the political climate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The political climate is not typically considered a direct determinant of the level of consumption. The level of consumption is primarily influenced by factors such as the expectation of price changes, the level of income, savings, and the rate of taxes paid. These factors have a direct impact on individuals' purchasing power and their ability and willingness to consume goods and services.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : CONSUMPTION FUNCTION"}, {"id": "objective>Economics>2024 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the standard deviation of a set of numbers is 3.6, what is the variance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12.69</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.9</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.96</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.98</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">S.d = √V <br/> Square both side: <br/>  <br/> Variance = (Sσ)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  <br/> Variance = 3.6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  <br/> V = 3.6  x 3.6 <br/>  <br/> Variance = 12.96</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2024 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The revolution of Cassava from ordinary food crop to export crop will lead to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease In production of cassava</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease In production of local starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase In production of other crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> increase in the prices of cassava products</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The recent revolution of cassava from an ordinary food crop to an export crop is likely to lead to an increase in the prices of cassava products. <br/>  <br/> When cassava transitions from being primarily used as a food crop to an export crop, its demand and value in the international market tend to increase. This increased demand can result in higher prices for cassava products such as cassava flour, starch, or other processed derivatives.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2024 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The formular (N + 1)/2 is used to determine the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">median</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standard deviation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The formula (N + 1)/2 is used to determine the median of a dataset. The median is the middle value in a set of ordered numbers. When the dataset has an odd number of values, the formula (N + 1)/2 helps identify the position of the median value. <br/>  <br/> N represents the total number of values in the dataset. By adding 1 to N and dividing it by 2, we get the position of the median value within the ordered set. <br/>  <br/> For example, if we have a dataset with 9 values, (N = 9), the position of the median would be (9 + 1)/2 = 10/2  <br/> = 5.  <br/> This means the fifth value in the ordered set would be the median.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH"}, {"id": "objective>Economics>2024 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the total product starts falling, then the marginal product is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> negative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal product refers to the additional output produced when one additional unit of input is added while keeping other inputs constant. When the total product starts falling, it means that the additional units of input are contributing less to the overall output, resulting in a decrease in the total product. <br/>  <br/> Since the marginal product is the change in total product divided by the change in input, a decrease in total product means the change in total product is negative. Therefore, the marginal product is negative when the total product is falling.</div>", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION"}, {"id": "objective>Economics>2024 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following can be used to improve a country's balance of payment EXCEPT</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">anti-dumping policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing taxation on personal income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granting subsidies to export producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing import duties</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Decreasing taxation on personal income is not typically a measure used to directly improve a country's balance of payments. The balance of payments refers to the record of a country's transactions with the rest of the world, including trade in goods and services, financial transactions, and transfers.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2024 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT a function of marketing boards in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fixing of prices for farm produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Grading of farm produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Importation of farm produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Marketing of farm produce</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marketing boards in Nigeria typically perform various functions related to the marketing and distribution of agricultural products. However, importation of farm produce is not a function usually associated with marketing boards in Nigeria. <br/>  <br/> Importation is typically managed by relevant government agencies responsible for trade and import policies, such as customs authorities or specialized trade departments.</div>", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS"}, {"id": "objective>Economics>2024 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The trade-off between two commodities along the Production Possibility Curve (PPC) shows</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost principle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarcity principle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transferable output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unattainable combination</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Production Possibility Curve represents the various combinations of two goods or commodities that can be produced with limited resources and technology. It reflects the trade-offs a society or individual faces when allocating resources between different goods or activities. <br/>  <br/> As you move along the PPC, producing more of one commodity requires sacrificing the production of the other commodity. This trade-off is known as the opportunity cost. The opportunity cost is the value of the next best alternative foregone when a choice is made. <br/>  <br/> For example, if an economy decides to produce more consumer goods, it must allocate fewer resources to producing capital goods. The opportunity cost of producing more consumer goods is the foregone production of capital goods.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>2024 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic problem arises as a result of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">choice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarcity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The economic problem arises as a result of scarcity. Scarcity refers to the condition where unlimited wants and needs exceed the limited resources available to fulfill them. In other words, resources such as land, labor, capital, and entrepreneurship are limited in comparison to the infinite desires and needs of individuals and society. <br/>  <br/> Because of scarcity, individuals, businesses, and societies must make choices about how to allocate their limited resources efficiently. This leads to the economic problem, which involves determining what to produce, how to produce it, and for whom to produce it.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2024 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an increase in the price of a commodity lead to a rise In the demand for the other, the demand for the two commodities are said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">competitive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">derived</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Competitive demand refers to a situation where two or more goods are seen as substitutes for each other. When the price of one commodity increases, consumers tend to shift their demand towards the substitute commodity, resulting in a decrease in the demand for the original commodity. <br/>  <br/> For example, if the price of coffee increases significantly, some consumers may choose to switch to tea as a substitute. As a result, the demand for coffee decreases while the demand for tea increases.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2024 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An industry engaged in the extraction of raw materials and its conversion into semi-finished goods is called industry.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conversion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">processing</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Processing involves transforming raw materials or inputs into more refined or semi-finished products. This can include various stages of production, such as refining, manufacturing, assembly, or other forms of processing. <br/>  <br/> The processing industry plays a vital role in taking raw materials from their natural state and converting them into products that can be used for further processing or consumed by end-users. This industry typically adds value to the raw materials by applying different processes, technologies, and expertise. <br/>  <br/> NOTE: Although manufacturing is involved in the production of goods, it does not specifically address the extraction of raw materials. Manufacturing encompasses a broader range of industries involved in producing finished goods from raw materials, components, or parts.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2024 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If two bags of rice were sold for #1,250 a month ago and two weeks later, the same amount was used to procure one bag. This simply means that the value of money is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluctuating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In this scenario, the price of rice has increased relative to the amount of money (N1,250) that could be used to purchase it. Initially, N1,250 could buy two bags of rice, but after two weeks, the same amount can only buy one bag. <br/>  <br/> This decrease in purchasing power demonstrates that the value of money has declined. In other words, the same amount of money can now buy fewer goods or services than before. This situation is often referred to as inflation, where the general price level of goods and services rises over time, reducing the purchasing power of money.</div>", "topic": "MONEY : VALUE OF MONEY"}, {"id": "objective>Economics>2024 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are the objectives of agricultural policies in Nigeria EXCEPT <br/> A. provision of food <br/> B. provision of agricultural raw materials to industrial sectors <br/> C. increasing prices of agricultural Inputs <br/> D. creation of rural employment</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provision of food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of agricultural raw materials to industrial sectors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing prices of agricultural Inputs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creation of rural employment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The objectives are:  provision of food, provision of agricultural raw materials to industrial sectors,  creation of rural employment. <br/>  <br/> However, increasing prices of agricultural inputs is not typically an objective of agricultural policies in Nigeria. Instead, policies often focus on measures to improve access to affordable agricultural inputs, such as seeds, fertilizers, and machinery, in order to support farmers and enhance productivity.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2024 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Stock exchange market deals with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">exchange of stock fish for stock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange of treasury bills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales of foreign exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales of second hand securities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The stock exchange market primarily deals with the sales of second-hand securities. It is a marketplace where individuals and institutions can buy and sell financial instruments, such as stocks, bonds, and derivatives. <br/>  <br/> The stock exchange provides a platform for investors to trade securities issued by companies, government entities, or other organizations. It facilitates the buying and selling of these securities between investors, allowing them to participate in the ownership of companies or debt instruments. <br/>  <br/> While the stock exchange market primarily focuses on the trading of stocks (equities), it also includes the trading of other securities such as bonds, mutual funds, exchange-traded funds (ETFs), options, and futures contracts.</div>", "topic": "FINANCIAL INSTITUTION : STOCK EXCHANGE"}, {"id": "objective>Economics>2024 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will NOT bring about an increase in Labour force?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Better medical services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decrease in death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Emigration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Immigration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Emigration refers to the act of leaving one's own country to permanently settle in another country. It typically involves individuals moving out of a particular country. Therefore, emigration would not bring about an increase in the labor force of the country from which people are emigrating.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2024 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT a major role of OPEC in production, and marketing of petroleum?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ensuring efficient and regular supply of oil to the two market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Raising the revenue of member countries from oil through price increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Refining of petroleum products in member countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stabilizing oil prices putting a production ceiling</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The refining of petroleum products is not a major role of OPEC (Organization of the Petroleum Exporting Countries) in the production and marketing of petroleum. OPEC primarily focuses on coordinating and unifying petroleum policies among its member countries, ensuring the efficient and regular supply of oil to the global market, raising the revenue of member countries through price increases, and stabilizing oil prices.</div>", "topic": "INTERNATIONAL TRADE : OPEC, ECA, IMF"}, {"id": "objective>Economics>2024 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT a function of the IMF?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">assisting member countries in printing and issuing their currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Exchange rate stabilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Promoting international monetary cooperation</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Providing financial aid to members experiencing balance of payment difficulties</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Assisting member countries in printing and issuing their currency is not a function of the International Monetary Fund (IMF). The IMF focuses on promoting international monetary cooperation, exchange rate stabilization, providing financial aid to countries with balance of payment difficulties, and serving as a clearing house for member countries.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IMF"}, {"id": "objective>Economics>2024 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The diagram above represent </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">National income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Circular flow of income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Business cycle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inflationary gap</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram represents the circular flow of a two sector economy which represent firms (Business sector) and Household (Private sector).</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2024 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> What add funds to the circular flow?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leakages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">injection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">withdrawal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Expenditure approach</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Injection refers to the economic activities that add fund or tend to increase planned aggregate demand, e.g.  Investment, government spending, export etc. <br/>  <br/> NOTE: Leakages also known as withdrawal and it refers to the out flow of the income or amount which reduces the amount of planned spending on domestic goods and service, e.g. savings, taxes, import etc. <br/> </div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INTRODUCTION"}, {"id": "objective>Economics>2024 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The system of farming which involves the use of a large hectare of land planted with economic crops is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mechanized farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peasant farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plantation farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tree planting</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The system of farming that involves the use of a large hectare of land planted with economic crops is known as plantation farming. In this type of farming, a single crop or a limited number of crops are cultivated on a large-scale agricultural estate or plantation. <br/>  <br/> Plantation farming typically involves the cultivation of crops such as tea, coffee, rubber, cocoa, sugarcane, palm oil, and various other cash crops. These crops are often grown for commercial purposes and are intended for sale in domestic or international markets. <br/>  <br/> Plantation farming is characterized by large-scale operations, extensive land use, and the application of mechanization, modern agricultural techniques, and sometimes even labor-intensive practices. It often requires significant capital investment, specialized machinery, and a well-organized management structure.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}];
